import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import ReactCrop from 'react-image-crop';
import 'react-image-crop/dist/ReactCrop.css';
import './Css/Admin.css';

const AdminDashboard = () => {
    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState('games'); 
    const [games, setGames] = useState([]);
    const [news, setNews] = useState([]);
    const [assets, setAssets] = useState({});

    // Forms
    const [newsForm, setNewsForm] = useState({ id: null, tag: '', title: '', description: '', image_url: '' });

    const fetchData = async () => {
        const [g, n, a] = await Promise.all([
            fetch('http://localhost:8000/api/top-games').then(r => r.json()),
            fetch('http://localhost:8000/api/news').then(r => r.json()),
            fetch('http://localhost:8000/api/assets').then(r => r.json())
        ]);
        setGames(g.games || []); setNews(n.news || []); setAssets(a.assets || {});
    };

    useEffect(() => { fetchData(); }, []);

    const updateBanner = async (key, url) => {
        await fetch(`http://localhost:8000/api/assets/${key}`, {
            method: 'PUT', headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ image_url: url })
        });
        fetchData();
    };

    const saveNews = async (e) => {
        e.preventDefault();
        await fetch(`http://localhost:8000/api/news/${newsForm.id}`, {
            method: 'PUT', headers: {'Content-Type': 'application/json'},
            body: JSON.stringify(newsForm)
        });
        setNewsForm({ id: null, tag: '', title: '', description: '', image_url: '' });
        fetchData();
    };

    return (
        <div className="admin-container">
            <header className="admin-header">
                <div className="logo">GAMING<span>HUB</span> CMS</div>
                <nav className="admin-tabs">
                    <span className={activeTab === 'games' ? 'active' : ''} onClick={() => setActiveTab('games')}>Manage Games</span>
                    <span className={activeTab === 'news' ? 'active' : ''} onClick={() => setActiveTab('news')}>Manage News</span>
                    <span className={activeTab === 'site' ? 'active' : ''} onClick={() => setActiveTab('site')}>Site Banners</span>
                </nav>
                <button className="logout-btn" onClick={() => navigate('/')}>Logout</button>
            </header>

            <div className="admin-content">
                {activeTab === 'games' && (
                    <div className="admin-card"><h2>Game Management</h2><p>Existing Games logic here...</p></div>
                )}

                {activeTab === 'news' && (
                    <div className="admin-grid-layout">
                        <section className="admin-card">
                            <h2>Edit Bento Card {newsForm.id}</h2>
                            <form onSubmit={saveNews} className="admin-form">
                                <input placeholder="Tag (BREAKING)" value={newsForm.tag} onChange={e => setNewsForm({...newsForm, tag: e.target.value})} />
                                <input placeholder="Title" value={newsForm.title} onChange={e => setNewsForm({...newsForm, title: e.target.value})} />
                                <textarea placeholder="Description" value={newsForm.description} onChange={e => setNewsForm({...newsForm, description: e.target.value})} />
                                <input placeholder="Image URL" value={newsForm.image_url} onChange={e => setNewsForm({...newsForm, image_url: e.target.value})} />
                                <button type="submit" className="add-btn">Update Card</button>
                            </form>
                        </section>
                        <section className="admin-card">
                            <h2>Current Grid</h2>
                            {news.map(n => (
                                <div key={n.id} className="admin-game-row" onClick={() => setNewsForm(n)}>
                                    <span>Slot {n.id}: {n.title || 'Empty'}</span>
                                    <button>Edit</button>
                                </div>
                            ))}
                        </section>
                    </div>
                )}

                {activeTab === 'site' && (
                    <div className="admin-card">
                        <h2>Login Page Banner</h2>
                        <input value={assets.login_banner || ''} onChange={e => updateBanner('login_banner', e.target.value)} placeholder="Image URL" />
                        <img src={assets.login_banner} style={{width:'300px', marginTop:'10px'}} alt="preview" />

                        <h2 style={{marginTop:'40px'}}>Landing Hero Image</h2>
                        <input value={assets.landing_hero || ''} onChange={e => updateBanner('landing_hero', e.target.value)} placeholder="Image URL" />
                        <img src={assets.landing_hero} style={{width:'300px', marginTop:'10px'}} alt="preview" />
                    </div>
                )}
            </div>
        </div>
    );
};

export default AdminDashboard;
